def H(t): return '<h2>%s</h2>' % t
def P(t): return '<p>%s</p>' % t
def pts(*items): return '<ul class="pts">%s</ul>' % ''.join('<li>%s</li>'%i for i in items)

import os as _os
def _LB(slug, fallback):
    fp = 'genwork/art-%s.py' % slug
    if _os.path.exists(fp):
        g = dict(globals())
        exec(open(fp, encoding='utf-8').read(), g)
        if g.get('BODY'):
            print('  [longread] %s загружен' % slug)
            return g['BODY']
    return fallback

