PRAKTIKI_JS = r'''<script>
(function(){
 function fmt(s){var m=Math.floor(s/60),ss=s%60;return m+':'+(ss<10?'0':'')+ss;}
 document.querySelectorAll('.pcard[data-type="breath"]').forEach(function(card){
   var inS=+card.dataset.in, holdS=+card.dataset.hold||0, outS=+card.dataset.out;
   var circle=card.querySelector('.pcircle'), label=card.querySelector('.plabel'),
       btn=card.querySelector('.pbtn'), sub=card.querySelector('.psub');
   var running=false, tos=[], t0=0, tick=null;
   function ph(name,dur,scale){ label.textContent=name; circle.style.transition='transform '+dur+'s ease-in-out'; circle.style.transform='scale('+scale+')'; }
   function cycle(){
     ph('Вдох',inS,1.55);
     tos.push(setTimeout(function(){
       if(holdS>0){ ph('Задержка',holdS,1.55); }
       tos.push(setTimeout(function(){
         ph('Выдох',outS,1.0);
         tos.push(setTimeout(cycle,outS*1000));
       }, holdS*1000));
     }, inS*1000));
   }
   function start(){ running=true; btn.textContent='Остановить'; card.classList.add('on'); t0=Date.now();
     tick=setInterval(function(){ if(sub){sub.textContent='идёт '+fmt(Math.floor((Date.now()-t0)/1000));} },1000); cycle(); }
   function stop(){ running=false; btn.textContent='Начать'; card.classList.remove('on');
     tos.forEach(clearTimeout); tos=[]; clearInterval(tick);
     circle.style.transition='transform .6s ease'; circle.style.transform='scale(1)'; label.textContent='Готов?'; if(sub)sub.textContent=''; }
   btn.onclick=function(){ running?stop():start(); };
 });
 document.querySelectorAll('.pcard[data-type="timer"]').forEach(function(card){
   var disp=card.querySelector('.tdisplay'), btn=card.querySelector('.pbtn'), presets=card.querySelectorAll('.tpresets button');
   var total=600,left=600,running=false,iv=null,done=false;
   function render(){ disp.textContent=done?'Готово':fmt(left); }
   presets.forEach(function(b){ b.onclick=function(){ if(running)return; done=false; card.classList.remove('done'); presets.forEach(function(x){x.classList.remove('sel')}); b.classList.add('sel'); total=Math.round(+b.dataset.min*60); left=total; btn.textContent='Начать'; render(); }; });
   function start(){ running=true; btn.textContent='Пауза'; var end=Date.now()+left*1000;
     iv=setInterval(function(){ left=Math.max(0,Math.round((end-Date.now())/1000)); render(); if(left<=0){ clearInterval(iv); running=false; done=true; card.classList.add('done'); btn.textContent='Заново'; render(); } },250); }
   function pause(){ running=false; btn.textContent='Продолжить'; clearInterval(iv); }
   btn.onclick=function(){ if(done){ done=false; card.classList.remove('done'); left=total; btn.textContent='Начать'; render(); return; } running?pause():start(); };
   var first=card.querySelector('.tpresets button'); if(first){ first.classList.add('sel'); total=Math.round(+first.dataset.min*60); left=total; } render();
 });
})();
</script>'''

def pcard_breath(chip,cls,title,desc,ins,hold,outs):
  return ('<div class="pcard" data-type="breath" data-in="%s" data-hold="%s" data-out="%s">'
    '<div class="ptop"><span class="chip %s">%s</span><h3>%s</h3></div><p>%s</p>'
    '<div class="pacer"><div class="pcircle"><span class="plabel">Готов?</span></div></div>'
    '<div class="psub"></div><button class="pbtn">Начать</button></div>')%(ins,hold,outs,cls,chip,title,desc)

def pcard_timer(chip,cls,title,desc,presets):
  pb=''.join('<button data-min="%s">%s</button>'%(m,l) for m,l in presets)
  return ('<div class="pcard" data-type="timer">'
    '<div class="ptop"><span class="chip %s">%s</span><h3>%s</h3></div><p>%s</p>'
    '<div class="tpresets">%s</div><div class="tdisplay">0:00</div>'
    '<button class="pbtn">Начать</button></div>')%(cls,chip,title,desc,pb)

